# Category: datastore_security

from elasticsearch import Elasticsearch
from flask import Flask, request

app = Flask(__name__)

# Initialize Elasticsearch client
es = Elasticsearch()

@app.route('/api/v1/dynamic-script', methods=['POST'])
def execute_dynamic_script():
    try:
        # Get script code from request
        script_code = request.json['script']

        # Execute script using Elasticsearch Script API
        result = es.search(
            index="your_index",  # Replace with your actual index
            body={
                "aggs": {
                    "dynamic_script": {
                        "script": {
                            "inline": script_code,
                            "lang": "painless"  # Replace with your actual script language
                        }
                    }
                }
            }
        )

        # Return the result
        return result
    except Exception as e:
        return {"error": str(e)}, 500

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)